// =====================================================
// Cottage Interior — a fully furnished small home.
// Stone walls + parquet floor; bed in the NW corner,
// living room with sofa + coffee table + chairs in the
// center, kitchen cabinet on the east, plants and lamps
// against the side walls, a green rug under the sofa.
// =====================================================

map CottageInterior {
  size 11, 10;

  // Wood-plank parquet floor
  fill FLOOR_PARQUET from (1,1) to (9,8);

  // Outer walls
  row WALL_STONE from (0,0) to (10,0);   // north
  row WALL_STONE from (0,0) to (0,9);    // west
  row WALL_STONE from (10,0) to (10,9);  // east

  // South wall — split around the door at col 5, plus windows at 2 and 8
  row WALL_STONE from (0,9) to (4,9);
  row WALL_STONE from (6,9) to (10,9);
  tile DOOR_WOOD   at (5,9);
  tile WINDOW_WOOD at (2,9);
  tile WINDOW_WOOD at (8,9);

  // ── Bedroom corner (NW) ───────────────────────────
  tile BED       at (1,2);
  tile RUG_GREEN at (2,2);          // small rug beside bed
  tile BOOKSHELF at (3,1);
  tile LAMP      at (3,3);          // bedside lamp

  // ── Kitchen corner (NE) ──────────────────────────
  tile CABINET    at (7,1);
  tile CABINET    at (8,1);
  tile PLANT      at (9,2);
  tile FRUIT_BOWL at (8,2);

  // ── Living room (center / south) ─────────────────
  tile SOFA  at (4,4);
  tile TABLE at (5,5);              // coffee table
  tile FRUIT_BOWL at (5,5);          // bowl on the table (drawn over it)
  tile CHAIR at (4,5);
  tile CHAIR at (6,5);
  tile RUG_GREEN at (4,6);
  tile RUG_GREEN at (5,6);
  tile RUG_GREEN at (6,6);

  // ── Side decorations ─────────────────────────────
  tile LAMP  at (1,7);              // SW lamp
  tile PLANT at (9,7);              // SE plant
  tile FLOWER at (1,6);             // flower beside lamp
  tile FLOWER at (9,6);

  // Portal back out — `back` returns to whichever map sent us here.
  portal at (5,9) -> back;

  // Player spawns just inside the door
  player at (5,8);
}
